Проблема была в неправильном апдейте поля template_uuid у репортов. В рамках задачи были восстановлены template_uuid на основании ссылки на отчет для нового формата в планировщике 

 
{code:java}
select result_link from interviews where result_link like 'https://interview-reports.deepmind.ai/________-____-____-____-____________/________-____-____-____-____________';
{code}
Далее по найденным данным создан маппинг report_uuid -> template_uuid [^result.json]

 

На его основе создан файл обновления сущностей [^updates.sql]

Далее убраны дублирующие настройки для деприкейтед шаблонов в пользу новых в планировщике, селект ниже не должен возвращать данные если все ок

 
{code:java}
SELECT ss.*
FROM section_settings ss
WHERE ss.setting_id IN (40, 42)
  AND ss.section_id IN (
    SELECT section_id
    FROM section_settings
    WHERE setting_id IN (40, 42)
    GROUP BY section_id
    HAVING COUNT(DISTINCT setting_id) = 2
);
{code}
 

Фидбек от пользователей об успешном восстановлении доступа получен(/)

Предварительный контракт для ручки - 
{code:java}
rpc assignBinding (AssignBindingIn) AssignBindingOut `Привязка источника оплаты к платежной сессии`

message AssignBindingIn {
    fintechClientID   string           `Идентификатор сервиса/проекта в FinTech. Создаётся во время согласования интеграции`
    transactionID     string
    bindingInterface  BindingInterface `Интерфейс привязки`
    payload          *bytes            `Доп. данные необходимые для привязки (маркировки, логист. данные ppo и т.д)`
}

message BindingInterface {
    paymentPage     *InterfacePaymentPage     `Передаётся в случае привязки через платёжную страницу` -- Пока не реализровано в финтехе, если на момент работы над задачей его не будет в финтехе то и у нас его тоже не будет
    oneClickBinding *InterfaceOneClickBinding `Передаётся в случае привязки через 1click и при привязке существующего источника`
}

message InterfaceOneClickBinding {
    successURL            string                 `URL, на который вернётся пользователь после успешной оплаты`
    failURL               string                 `URL, на который вернётся пользователь после неуспешной оплаты`
    title                *string                 `Назначение платежа`
    platform              Platform               `Платформа, с которой сделан заказ`
    paymentMethod        *PaymentMethodV2        `Метод оплаты`
    paymentMethodDetails *PaymentMethodDetailsV2 `Дополнительные данные в зависимости от метода оплаты`
    bindingID            *string                 `Идентификатор существующего источника оплаты`
    buyer                 BindingByuer           `Пользователь владелец привязанного источника оплаты`
}

message BindingByuer {
    //brief:sensitive USER_ID
    id     int    `DeepMind ID покупателя`
    //brief:sensitive EMAIL
    email *string `Email, на который приходит чек`
    //brief:sensitive PHONE
    phone *string `Номер телефона`
}

message AssignBindingOut {
    error                  *Error
    fintechRequestID       *string                    `ID операции в FinTech`
    assignBindingInterface  AssignBindingInterfaceOut `Будет заполнена структура соответсвующая входяшему интерфейсу в запросе`
}

message AssignBindingInterfaceOut {
    paymentPage *InterfacePaymentPageOut    `Передаётся в случае привязки нового источника оплаты`
    oneClick    *InterfaceOneClickLegacyOut `Передаётся в случае привязки через 1click`
}
 {code}

